const downloadUrl=(id)=>{const u=new URL(`/api/items/${id}/download`,window.location.origin),uid=userId();if(uid)u.searchParams.set('user_id',String(uid));return u.toString();};
function install(i){setInstalled(i.id);render();if(s.selected===i.id)detail(s.cache.get(i.id)||i);tg?.HapticFeedback?.impactOccurred?.('light');if(tg&&typeof tg.sendData==='function'){try{tg.sendData(JSON.stringify({action:'download_in_bot',item_id:i.id}));return;}catch(err){console.error('sendData failed',err);}}const u=downloadUrl(i.id);if(tg?.openLink){tg.openLink(u);return;}window.open(u,'_blank','noopener');}
function screenshots(i){const media=[...(i.cover_url?[i.cover_url]:[]),...(i.screenshots||[])].filter(Boolean).filter((src,idx,arr)=>arr.indexOf(src)===idx);if(!media.length)return `<div class="shot-rail">${Array.from({length:3}).map((_,x)=>`<article class="shot-card" style="${vars(i)}"><span>${esc(L().act.preview)} ${x+1}</span><strong>${esc(L().act.noShots)}</strong></article>`).join('')}</div>`;return `<div class="shot-rail">${media.map((src,idx)=>`<article class="shot-card is-image"><img src="${esc(src)}" alt="${esc(i.name)} screenshot ${idx+1}" loading="lazy" /><span>${esc(L().act.preview)} ${idx+1}</span></article>`).join('')}</div>`;}
function detail(i){const full=s.cache.get(i.id)||i,rel=(full.related||[]).slice(0,4),about=i.type==='game'?L().act.aboutGame:L().act.aboutApp,note=i.source_host?`${L().act.source}: ${i.source_host}`:L().act.available;e.detail.innerHTML=`<div class="detail-banner ${i.cover_url?'has-cover':''}" style="${vars(i)}">${i.cover_url?`<div class="detail-banner-media"><img src="${esc(i.cover_url)}" alt="${esc(i.name)} cover" loading="lazy" /></div>`:''}<div class="detail-banner-copy"><div class="detail-kicker">${esc(i.type==='game'?L().tabs.games:L().tabs.apps)}</div><h2>${esc(i.name)}</h2><p>${esc(i.description||meta(i))}</p></div></div><div class="detail-head">${icon(i,'detail-icon')}<div class="detail-meta"><h3>${esc(i.name)}</h3><p>${esc(meta(i))}</p><span>${esc(note)}</span></div>${button(i,'large')}</div><div class="stats-grid"><div class="stat-card"><strong>${esc(rating(i))}</strong><span>${esc(L().act.rating)}</span></div><div class="stat-card"><strong>${esc(i.size)}</strong><span>${esc(L().act.size)}</span></div><div class="stat-card"><strong>${esc(catLabel(i.category))}</strong><span>${esc(L().act.category)}</span></div><div class="stat-card"><strong>${esc(i.version)}</strong><span>${esc(L().act.version)}</span></div></div><section class="detail-section"><div class="detail-section-head"><h4>${esc(L().act.screens)}</h4></div>${screenshots(i)}</section><section class="detail-section"><div class="detail-section-head"><h4>${esc(about)}</h4></div><p class="detail-description">${esc(i.description||`${typeLabel(i.type)} \u2022 ${i.developer}`)}</p></section>${rel.length?`<section class="detail-section"><div class="detail-section-head"><h4>${esc(L().act.related)}</h4></div><div class="detail-related">${rel.map((x)=>row(x)).join('')}</div></section>`:''}`;}
async function openDetail(id){const local=item(id);if(!local)return;s.selected=id;toggleSheet(true);e.detail.innerHTML=`<div class="detail-banner" style="${vars(local)}"><div class="detail-banner-copy"><div class="detail-kicker">${esc(L().act.loadingDetail)}</div><h2>${esc(local.name)}</h2><p>${esc(local.description||meta(local))}</p></div></div>`;try{const r=await fetch(`/api/items/${id}`);if(!r.ok)throw new Error(`HTTP ${r.status}`);const full=prep(await r.json());full.related=(full.related||[]).map(prep);s.cache.set(id,full);detail(full);}catch(err){console.error('detail load failed',err);detail({...local,related:sortByScore(s.items.filter((x)=>x.id!==local.id&&(x.category===local.category||x.type===local.type))).slice(0,6)});}}
function closeDetail(){s.selected=null;toggleSheet(false);}
function onTap(ev){const installBtn=ev.target.closest('[data-action="install"]');if(installBtn){ev.preventDefault();ev.stopPropagation();const i=item(installBtn.dataset.id);if(i)install(i);return;}const jump=ev.target.closest('[data-jump]');if(jump){setScreen(jump.dataset.jump);return;}const trend=ev.target.closest('[data-trend]');if(trend){setScreen('search');s.query='';s.filter.search=trend.dataset.trend||'all';render();return;}const card=ev.target.closest('[data-id]');if(card)openDetail(Number(card.dataset.id));}
function sakura(){if(!e.sakura||window.matchMedia('(prefers-reduced-motion: reduce)').matches)return;e.sakura.innerHTML='';for(let i=0;i<12;i+=1){const p=document.createElement('span');p.className='sakura-petal';p.style.left=`${Math.random()*100}%`;p.style.setProperty('--delay',`${Math.random()*6}s`);p.style.setProperty('--duration',`${8+Math.random()*6}s`);p.style.setProperty('--drift',`${(Math.random()*2-1)*160}px`);p.style.setProperty('--scale',`${0.8+Math.random()*0.6}`);e.sakura.appendChild(p);}}
function bind(){e.bottom.addEventListener('click',(ev)=>{const b=ev.target.closest('.tab-button');if(b)setScreen(b.dataset.screen);});e.searchInput.addEventListener('input',(ev)=>{s.query=ev.target.value||'';render();});e.searchClear.addEventListener('click',()=>{s.query='';e.searchInput.value='';render();});e.filterTrack.addEventListener('click',(ev)=>{const b=ev.target.closest('[data-filter]');if(!b)return;s.filter[s.screen]=b.dataset.filter||'all';render();});e.hero.addEventListener('click',onTap);e.stack.addEventListener('click',onTap);e.detail.addEventListener('click',onTap);e.menuBtn.addEventListener('click',()=>toggleMenu(true));e.profileButton?.addEventListener('click',()=>toggleMenu(true));e.menuClose.addEventListener('click',()=>toggleMenu(false));e.menuScrim.addEventListener('click',()=>toggleMenu(false));e.sheetScrim.addEventListener('click',closeDetail);e.sheetClose.addEventListener('click',closeDetail);e.policyToggle.addEventListener('click',()=>{s.policy=!s.policy;e.policyPanel.hidden=!s.policy;});e.langControl.addEventListener('click',(ev)=>{const b=ev.target.closest('[data-role="lang"]');if(!b)return;s.lang=b.dataset.lang==='en'?'en':'ru';localStorage.setItem(KEY.lang,s.lang);applyCopy();render();if(s.selected)openDetail(s.selected);});e.themeControl.addEventListener('click',(ev)=>{const b=ev.target.closest('[data-role="theme"]');if(!b)return;s.theme=b.dataset.theme==='light'?'light':'dark';localStorage.setItem(KEY.theme,s.theme);applyTheme();});e.authTabs?.addEventListener('click',(ev)=>{const b=ev.target.closest('[data-auth-tab]');if(b)setAuthTab(b.dataset.authTab);});e.signInForm?.addEventListener('submit',handleSignIn);e.signUpForm?.addEventListener('submit',handleSignUp);e.authTelegram?.addEventListener('click',useTelegramAuth);e.authGuest?.addEventListener('click',useGuestAuth);const f=forgotEls();f.button?.addEventListener('click',()=>{if(f.form)f.form.hidden=false;setAuthStatus('Enter email to get reset token, then set a new password.',true);});f.back?.addEventListener('click',()=>{if(f.form)f.form.hidden=true;setAuthStatus(authText().hint);});f.form?.addEventListener('submit',async(ev)=>{ev.preventDefault();const email=f.email?.value.trim()||'',token=f.token?.value.trim()||'',password=f.password?.value.trim()||'';try{if(token&&password){const data=await authRequest('/api/auth/reset-password',{token,password});completeAuth(data.user,'Password changed. You are signed in.');return;}if(!authEmailValid(email))return setAuthStatus('Enter a valid email.',true);const data=await authRequest('/api/auth/forgot-password',{email});if(f.token&&data.reset_token)f.token.value=data.reset_token;setAuthStatus(data.reset_token?`Reset token: ${data.reset_token}`:'If the account exists, reset data was created.',true);}catch(err){setAuthStatus('Reset failed: '+err.message,true);}});document.addEventListener('keydown',(ev)=>{if(ev.key==='Escape'){toggleMenu(false);closeDetail();}});}
async function init(){applyTheme();applyCopy();header();tick();bind();sakura();startAuthBackground();startAuthConsole();renderLoading();try{const r=await fetch('/api/auth/me',{credentials:'same-origin'});if(r.ok){const data=await r.json();saveAuth(data.user);showApp();}else if(s.auth){showApp();}else showAuth();}catch(_){if(s.auth)showApp();else showAuth();}setInterval(tick,30000);}
init();

function renderAccountCard(){const old=document.getElementById('accountCard');if(old)old.remove();if(!s.auth)return;const support=document.querySelector('.menu-support');if(!support)return;const a=authText();const card=document.createElement('section');card.className='account-card';card.id='accountCard';card.innerHTML=`<div class="account-kicker">${esc(a.account)}</div><div class="account-name">${esc(s.auth.name||'Guest')}</div><div class="account-email">${esc(s.auth.email||'local@device')}</div><button class="account-signout" id="accountSignOut" type="button">${esc(a.signOut)}</button>`;support.before(card);document.getElementById('accountSignOut')?.addEventListener('click',signOut);}
function setAuthStatus(msg,persistent=false){if(!e.authStatus)return;e.authStatus.textContent=msg;e.authStatus.dataset.userState=persistent?'1':'';}
function setAuthTab(tab){s.authTab=tab==='signup'?'signup':'signin';e.tabSignIn?.classList.toggle('active',s.authTab==='signin');e.tabSignUp?.classList.toggle('active',s.authTab==='signup');e.signInForm?.classList.toggle('active',s.authTab==='signin');e.signUpForm?.classList.toggle('active',s.authTab==='signup');if(e.signInForm)e.signInForm.hidden=s.authTab!=='signin';if(e.signUpForm)e.signUpForm.hidden=s.authTab!=='signup';}
function showApp(){document.body.classList.remove('auth-active');if(e.authShell)e.authShell.hidden=true;renderAccountCard();if(!s.loaded)load();}
function showAuth(){document.body.classList.add('auth-active');if(e.authShell)e.authShell.hidden=false;setAuthTab(s.authTab);const f=forgotEls();if(f.form)f.form.hidden=true;setAuthStatus(authText().hint);}
function completeAuth(profile,message){saveAuth(profile);e.profileCore.textContent=authName().trim().charAt(0).toUpperCase()||'A';setAuthStatus(message,true);showApp();}
async function signOut(){try{await fetch('/api/auth/logout',{method:'POST',credentials:'same-origin'});}catch(_){}clearAuth();toggleMenu(false);showAuth();}
async function handleSignIn(ev){ev.preventDefault();const login=e.signInLogin?.value.trim()||'',password=e.signInPassword?.value.trim()||'',remember=!!forgotEls().remember?.checked;if(!login||!password)return setAuthStatus(authText().badLogin,true);try{const data=await authRequest('/api/auth/login',{login,password,remember_me:remember});completeAuth(data.user,authText().signedIn);}catch(err){setAuthStatus('Login failed: '+err.message,true);}}
async function handleSignUp(ev){ev.preventDefault();const name=e.signUpName?.value.trim()||'',email=e.signUpEmail?.value.trim()||'',password=e.signUpPassword?.value.trim()||'',remember=!!forgotEls().rememberSignUp?.checked;if(!name||!authEmailValid(email)||password.length<6)return setAuthStatus(authText().badSignup,true);try{const username=name.toLowerCase().replace(/[^a-z0-9]+/g,'.').replace(/^\.+|\.+$/g,'').slice(0,24)||'user';const data=await authRequest('/api/auth/register',{display_name:name,email,password,username,remember_me:remember});completeAuth(data.user,authText().signedUp);}catch(err){setAuthStatus('Register failed: '+err.message,true);}}
async function useTelegramAuth(){const user=tg?.initDataUnsafe?.user;if(!user)return setAuthStatus(authText().hint,true);const name=[user.first_name,user.last_name].filter(Boolean).join(' ')||user.username||'Telegram User';const email=user.username?`${user.username}@telegram.local`:`telegram-${user.id||'user'}@local.dev`;try{const data=await authRequest('/api/auth/register',{display_name:name,email,password:`tg-${user.id||'user'}-secret`,username:user.username||name.toLowerCase().replace(/[^a-z0-9]+/g,'.'),remember_me:true});completeAuth(data.user,authText().telegramReady);}catch(err){try{const data=await authRequest('/api/auth/login',{login:email,password:`tg-${user.id||'user'}-secret`,remember_me:true});completeAuth(data.user,authText().telegramReady);}catch(err2){setAuthStatus('Telegram auth failed',true);}}}

async function useTelegramAuth(){
	// Prefer real Telegram WebApp context when available
	let user = tg?.initDataUnsafe?.user;

	// Development fallback: simulate a Telegram user when running locally
	if(!user){
		console.warn('Telegram WebApp not detected — using local fallback profile for dev.');
		setAuthStatus('Using local Telegram fallback for development...', true);
		user = {
			id: 999999999,
			first_name: 'Local',
			last_name: 'Dev',
			username: 'local_telegram'
		};
	}

	const name = [user.first_name, user.last_name].filter(Boolean).join(' ') || user.username || 'Telegram User';
	const email = user.username ? `${user.username}@telegram.local` : `telegram-${user.id || 'user'}@local.dev`;
	const password = `tg-${user.id || 'user'}-secret`;
	const username = (user.username || name.toLowerCase().replace(/[^a-z0-9]+/g,'.')).slice(0,24) || 'user';

	try{
		const data = await authRequest('/api/auth/register', {display_name: name, email, password, username, remember_me: true});
		completeAuth(data.user, authText().telegramReady);
	} catch (err) {
		// If register fails (user exists), try login
		try{
			const data = await authRequest('/api/auth/login', {login: email, password, remember_me: true});
			completeAuth(data.user, authText().telegramReady);
		} catch (err2) {
			console.error('Telegram auth error:', err, err2);
			setAuthStatus('Telegram auth failed: ' + (err2.message || err.message || 'unknown'), true);
		}
	}
}
function useGuestAuth(){const name=tg?.initDataUnsafe?.user?.first_name||'Guest';completeAuth({mode:'guest',name,email:'guest@local.dev'},authText().guestReady);}
function startAuthBackground(){const canvas=e.authCanvas;if(!canvas)return;const ctx=canvas.getContext('2d');if(!ctx)return;const particles=[],count=18;const resize=()=>{canvas.width=window.innerWidth;canvas.height=window.innerHeight;particles.length=0;for(let i=0;i<count;i+=1)particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height,z:400+Math.random()*2200,speed:4+Math.random()*4,size:80+Math.random()*200});};const frame=()=>{ctx.clearRect(0,0,canvas.width,canvas.height);ctx.lineWidth=1;particles.forEach((p)=>{p.z-=p.speed;if(p.z<100)p.z=2600;const scale=420/p.z,w=p.size*scale,h=w*0.58,x=(p.x-canvas.width/2)*scale+canvas.width/2,y=(p.y-canvas.height/2)*scale+canvas.height/2;ctx.strokeStyle=`rgba(110,255,226,${Math.min(0.48,scale*1.5)})`;ctx.strokeRect(x-w/2,y-h/2,w,h);});ctx.beginPath();ctx.strokeStyle='rgba(80,190,255,0.2)';const baseY=canvas.height*0.22;ctx.moveTo(0,baseY);for(let i=0;i<canvas.width;i+=12)ctx.lineTo(i,baseY+Math.sin((Date.now()*0.0018)+i*0.03)*10);ctx.stroke();requestAnimationFrame(frame);};resize();frame();window.addEventListener('resize',resize);}
function startAuthConsole(){if(!e.authConsole||window.matchMedia('(prefers-reduced-motion: reduce)').matches)return;const queue=[...authText().console],extras=['Auth checkpoint OK','Device fingerprint cached','Store token staged','Local preferences restored'];const push=()=>{const line=document.createElement('p');const pool=queue.length?queue:extras;line.textContent=`[${new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit',second:'2-digit'})}] ${pool[Math.floor(Math.random()*pool.length)]}`;e.authConsole.appendChild(line);while(e.authConsole.children.length>8)e.authConsole.removeChild(e.authConsole.firstChild);setTimeout(push,800+Math.random()*900);};push();}
// New signup flow: request email code, verify, then register
async function handleSignUpNew(ev){
	ev.preventDefault();
	const name = e.signUpName?.value.trim() || '';
	const email = e.signUpEmail?.value.trim() || '';
	const password = e.signUpPassword?.value.trim() || '';
	const remember = !!forgotEls().rememberSignUp?.checked;

	if (!name || !authEmailValid(email) || password.length < 6) return setAuthStatus(authText().badSignup, true);

	try {
		const send = await authRequest('/api/auth/send-code', { email });
		if (send.debug_code) console.info('Verification code (debug):', send.debug_code);

		const code = prompt('Enter the 6-digit verification code sent to your email');
		if (!code) return setAuthStatus('Verification cancelled', true);

		await authRequest('/api/auth/verify-code', { email, code });

		const username = name.toLowerCase().replace(/[^a-z0-9]+/g, '.').replace(/^\.+|\.+$/g, '').slice(0, 24) || 'user';
		const data = await authRequest('/api/auth/register', { display_name: name, email, password, username, remember_me: remember });
		completeAuth(data.user, authText().signedUp);
	} catch (err) {
		setAuthStatus('Register failed: ' + err.message, true);
	}
}

// Replace existing signup listener (if already bound) with new handler
(function swapSignupListener(){
	try{
		const form = document.getElementById('signUpForm');
		if(!form) return;
		form.removeEventListener('submit', handleSignUp);
		form.addEventListener('submit', handleSignUpNew);
	}catch(e){console.warn('swapSignupListener failed',e);}
})();



